pub fn get_move_by_name(name: &str) -> Option<&'static MoveData> {
    MOVE_DATA.iter().find(|m| m.name.eq_ignore_ascii_case(name))
}

pub fn get_move_by_id(id: u16) -> Option<&'static MoveData> {
    MOVE_DATA.iter().find(|m| m.id == id)
}
